const PROCESSING_FEE = 5;

interface Item {
  type: string;
}

interface Step {
  op: string;
  items?: Item[];
}

interface Scenario {
  steps: Step[];
}

const basePremium = (item: Item): number => {
  if (item.type === "sword") return 100;
  return 0;
};

export const runScenario = (scenario: Scenario): unknown => {
  const results = scenario.steps.map((step) => {
    const items = step.items ?? [];
    const total = items.reduce((sum, i) => sum + basePremium(i), 0);
    return { premium: total + PROCESSING_FEE };
  });
  return { results };
};

