const PROCESSING_FEE = 5;

interface Item {
  type: string;
}

interface Step {
  op: string;
  items?: Item[];
}

interface Scenario {
  steps: Step[];
}

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const basePremium = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;

export const runScenario = (scenario: Scenario): unknown => {
  const results = scenario.steps.map((step) => {
    const items = step.items ?? [];
    const total = items.reduce((sum, item) => sum + basePremium(item), 0);
    return { premium: total + PROCESSING_FEE };
  });
  return { results };
};

