const COMPONENT_TYPES = new Set(["rune"]);
const BLOCK_SIZE = 3;
const BLOCK_PRICE = 60;

const itemsBasePremium = (items: Item[]): number => {
  const components = items.filter((i) => COMPONENT_TYPES.has(i.type));
  const mainItems = items.filter((i) => !COMPONENT_TYPES.has(i.type));
  let total = mainItems.reduce((sum, item) => sum + basePremium(item), 0);
  const byType: Record<string, number> = {};
  for (const c of components) byType[c.type] = (byType[c.type] ?? 0) + 1;
  for (const type of Object.keys(byType)) {
    const count = byType[type];
    if (count === BLOCK_SIZE) {
      total += BLOCK_PRICE;
    } else {
      total += count * basePremium({ type });
    }
  }
  return total;
};

export const runScenario = (scenario: Scenario): unknown => {
  const results = scenario.steps.map((step) => {
    const items = step.items ?? [];
    const total = itemsBasePremium(items);
    return { premium: total + PROCESSING_FEE };
  });
  return { results };
};

