import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Quote: empty and single-item basics
  it("quote with empty item list returns premium 5 (processing fee only)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result).toEqual({ results: [{ premium: 5 }] });
  });
  it("quote with a single plain sword returns premium 105", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 1, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 105 }] });
  });
  it("quote with a single plain amulet returns premium 65", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "amulet", material: "silver", enchantment: 1, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 65 }] });
  });
  it("quote with a single plain staff returns premium 85", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "staff", material: "wood", enchantment: 1, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 85 }] });
  });
  it("quote with a single plain potion returns premium 45", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "potion", material: "glass", enchantment: 1, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 45 }] });
  });

  // Quote: multiple items
  it("quote with sword + amulet sums base premiums plus fee → 165", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "sword", material: "steel", enchantment: 1, cursed: false },
            { type: "amulet", material: "silver", enchantment: 1, cursed: false },
          ],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 165 }] });
  });

  // Components and block-of-3
  it("quote with a single rune returns 25 + 5 = 30", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 30 }] });
  });
  it("quote with 2 runes returns 50 + 5 = 55", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 55 }] });
  });
  it("quote with 3 runes (block) returns 60 + 5 = 65", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 65 }] });
  });
  it("quote with 4 runes returns 100 + 5 = 105", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 105 }] });
  });
  it("quote with 7 runes returns 175 + 5 = 180", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: Array.from({ length: 7 }, () => ({ type: "rune" })),
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 180 }] });
  });
  it("quote with 2 runes + 1 moonstone returns 75 + 5 = 80", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 80 }] });
  });
  it("quote with 3 runes + 3 moonstones returns 120 + 5 = 125", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "rune" },
            { type: "rune" },
            { type: "rune" },
            { type: "moonstone" },
            { type: "moonstone" },
            { type: "moonstone" },
          ],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 125 }] });
  });

  // Item-specific modifiers
  it("cursed sword (steel, enchantment 3, newcomer) → premium 165", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 3, cursed: true }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 165 }] });
  });
  it.todo("sword with enchantment 5 (newcomer) → 100 + 30 = 130 + 5 fee = 135");
  it.todo("sword with enchantment 4 (newcomer) → no high-ench surcharge → 105");

  // Policy-wide modifiers
  it.todo("loyalty discount: 2-year customer with plain sword → 100 − 20 + 5 = 85");
  it.todo("first-insurance surcharge: each item in quote adds 10% of its base");
  it.todo("follow-up contract: 15% discount applies on second quote");

  // Integration
  it.todo("newcomer cursed sword integration example → 165");
  it.todo("long-standing customer's second contract cursed enchanted sword → 160");

  // Rounding
  it.todo("premium that yields 197.5 rounds up to 198");

  // Errors
  it.todo("quote with unknown item type exits non-zero with stderr message");

  // Claim: basic
  it.todo("claim on plain sword, damage 500 → payout 400, remainingCap 1600");
  it.todo("claim on rune, damage 200 → payout 100");

  // Claim: special clauses
  it.todo("dragon-material sword enchantment 5, damage 800 → payout 700");
  it.todo("steel sword enchantment 9, damage 1000 → payout 400");
  it.todo("dragon-material sword enchantment 9, damage 1000 → payout 400");
  it.todo("dragon-material sword enchantment 8, damage 1000 → payout 400");

  // Multiple damages and deductible
  it.todo("dragon attack damaging sword 500 and amulet 300 → payout 600");

  // Multiple items of same type
  it.todo("policy with two swords, both damaged → each has own deductible");
  it.todo("damages with more entries of a type than insured → CLI exits non-zero");

  // Cap exhaustion
  it.todo("sword cap 2000; two claims of 1500 → 1400 then 600");

  // Claim errors
  it.todo("claim references item not in policy → CLI exits non-zero");
  it.todo("claim with negative amount → CLI exits non-zero");

  // Rounding payout
  it.todo("payout that yields 350.5 rounds down to 350");
});

