       type: string;
       material?: string;
       enchantment?: number;
       cursed?: boolean;
     }

     interface Step {
       op: string;
       items?: Item[];
     }

     interface Customer {
       yearsWithMHPCO: number;
     }

     interface Scenario {
       customer: Customer;
       steps: Step[];
     }

     const BASE_PREMIUMS: Record<string, number> = {
       sword: 100, amulet: 60, staff: 80, potion: 40, rune: 25, moonstone: 25,
     };

     const basePremium = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;

