import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Quote: empty and single-item basics
  it("quote with empty item list returns premium 5 (processing fee only)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result).toEqual({ results: [{ premium: 5 }] });
  });
  it("quote with a single plain sword returns premium 115", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 1, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("quote with a single plain amulet returns premium 71", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "amulet", material: "silver", enchantment: 1, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it("quote with a single plain staff returns premium 93", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "staff", material: "wood", enchantment: 1, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 93 }] });
  });
  it("quote with a single plain potion returns premium 49", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "potion", material: "glass", enchantment: 1, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 49 }] });
  });

  // Quote: multiple items
  it("quote with sword + amulet sums base premiums plus first-insurance + fee → 181", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "sword", material: "steel", enchantment: 1, cursed: false },
            { type: "amulet", material: "silver", enchantment: 1, cursed: false },
          ],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 181 }] });
  });

  // Components and block-of-3
  it("quote with a single rune returns 25 + first-insurance + 5 → 33", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 33 }] });
  });
  it("quote with 2 runes returns 50 + first-insurance + 5 → 60", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 60 }] });
  });
  it("quote with 3 runes (block) returns 60 + first-insurance + 5 → 71", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it("quote with 4 runes returns 100 + first-insurance + 5 → 115", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("quote with 7 runes returns 175 + first-insurance + 5 → 198", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: Array.from({ length: 7 }, () => ({ type: "rune" })),
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 198 }] });
  });
  it("quote with 2 runes + 1 moonstone returns 75 + first-insurance + 5 → 88", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 88 }] });
  });
  it("quote with 3 runes + 3 moonstones returns 120 + first-insurance + 5 → 137", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "rune" },
            { type: "rune" },
            { type: "rune" },
            { type: "moonstone" },
            { type: "moonstone" },
            { type: "moonstone" },
          ],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 137 }] });
  });

  // Item-specific modifiers
  it("cursed sword (steel, enchantment 3, newcomer) → premium 165", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 3, cursed: true }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 165 }] });
  });
  it("sword with enchantment 5 (newcomer) → 100 + 30 high-ench + 10 first-ins + 5 fee = 145", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 5, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 145 }] });
  });
  it("sword with enchantment 4 (newcomer) → no high-ench surcharge → 115", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 4, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });

  // Policy-wide modifiers
  it("loyalty discount: 2-year customer with plain sword → 100 + 10 first-ins − 20 loyalty + 5 fee = 95", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 2 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 1, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 95 }] });
  });
  it("follow-up contract: 15% discount applies on second quote (newcomer, plain sword)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 1, cursed: false }],
        },
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 1, cursed: false }],
        },
      ],
    });
    // First quote: 100 + 10 first-ins + 5 = 115
    // Second quote: 100 + 10 first-ins - 15 follow-up + 5 = 100
    expect(result).toEqual({ results: [{ premium: 115 }, { premium: 100 }] });
  });

  // Integration
  it("long-standing customer's second contract cursed enchanted sword → 160", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 3 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 1, cursed: false }],
        },
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 7, cursed: true }],
        },
      ],
    });
    // Second quote: 100 + 50 curse + 30 high-ench - 20 loyalty + 10 first-ins - 15 follow-up + 5 fee = 160
    expect((result as { results: unknown[] }).results[1]).toEqual({ premium: 160 });
  });

  // Errors
  it("quote with unknown item type throws an error", () => {
    expect(() =>
      runScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [{ op: "quote", items: [{ type: "broomstick" }] }],
      }),
    ).toThrow();
  });

  // Claim: basic
  it.todo("claim on plain sword, damage 500 → payout 400, remainingCap 1600");
  it.todo("claim on rune, damage 200 → payout 100");

  // Claim: special clauses
  it.todo("dragon-material sword enchantment 5, damage 800 → payout 700");
  it.todo("steel sword enchantment 9, damage 1000 → payout 400");
  it.todo("dragon-material sword enchantment 9, damage 1000 → payout 400");
  it.todo("dragon-material sword enchantment 8, damage 1000 → payout 400");

  // Multiple damages and deductible
  it.todo("dragon attack damaging sword 500 and amulet 300 → payout 600");

  // Multiple items of same type
  it.todo("policy with two swords, both damaged → each has own deductible");
  it.todo("damages with more entries of a type than insured → CLI exits non-zero");

  // Cap exhaustion
  it.todo("sword cap 2000; two claims of 1500 → 1400 then 600");

  // Claim errors
  it.todo("claim references item not in policy → CLI exits non-zero");
  it.todo("claim with negative amount → CLI exits non-zero");

  // Rounding payout
  it.todo("payout that yields 350.5 rounds down to 350");
});

const PROCESSING_FEE = 5;

interface Item {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
}

interface Step {
  op: string;
  items?: Item[];
}

interface Customer {
  yearsWithMHPCO: number;
}

interface Scenario {
  customer: Customer;
  steps: Step[];
}

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const basePremium = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const BLOCK_SIZE = 3;
const BLOCK_PRICE = 60;

const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);

const countByType = (items: Item[]): Record<string, number> =>
  items.reduce<Record<string, number>>((counts, item) => {
    counts[item.type] = (counts[item.type] ?? 0) + 1;
    return counts;
  }, {});

const componentGroupPremium = (type: string, count: number): number =>
  count === BLOCK_SIZE ? BLOCK_PRICE : count * basePremium({ type });

const componentsPremium = (components: Item[]): number => {
  const counts = countByType(components);
  return Object.entries(counts).reduce(
    (sum, [type, count]) => sum + componentGroupPremium(type, count),
    0,
  );
};

const CURSED_SURCHARGE_RATE = 0.5;
const HIGH_ENCHANTMENT_THRESHOLD = 5;
const HIGH_ENCHANTMENT_RATE = 0.3;
const FIRST_INSURANCE_RATE = 0.1;
const LOYALTY_YEARS_THRESHOLD = 2;
const LOYALTY_DISCOUNT_RATE = 0.2;
const FOLLOWUP_DISCOUNT_RATE = 0.15;

const itemSurcharges = (item: Item): number => {
  const base = basePremium(item);
  let extras = 0;
  if (item.cursed) extras += base * CURSED_SURCHARGE_RATE;
  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
    extras += base * HIGH_ENCHANTMENT_RATE;
  }
  return extras;
};

const itemsBasePremium = (items: Item[]): number => {
  const mainItems = items.filter((i) => !isComponent(i));
  const components = items.filter(isComponent);
  const mainTotal = mainItems.reduce(
    (sum, item) => sum + basePremium(item) + itemSurcharges(item),
    0,
  );
  return mainTotal + componentsPremium(components);
};

const policyBaseSum = (items: Item[]): number => {
  const mainBase = items.filter((i) => !isComponent(i)).reduce((s, i) => s + basePremium(i), 0);
  const compBase = componentsPremium(items.filter(isComponent));
  return mainBase + compBase;
};

const policyModifiers = (
  customer: Customer,
  policyBase: number,
  isFollowUp: boolean,
): number => {
  let modifiers = policyBase * FIRST_INSURANCE_RATE;
  if (customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD) {
    modifiers -= policyBase * LOYALTY_DISCOUNT_RATE;
  }
  if (isFollowUp) {
    modifiers -= policyBase * FOLLOWUP_DISCOUNT_RATE;
  }
  return modifiers;
};

const computeQuotePremium = (
  customer: Customer,
  items: Item[],
  isFollowUp: boolean,
): number => {
  const itemsWithSurcharges = itemsBasePremium(items);
  const policyBase = policyBaseSum(items);
  const raw =
    itemsWithSurcharges + policyModifiers(customer, policyBase, isFollowUp) + PROCESSING_FEE;
  return Math.ceil(raw);
};

export const runScenario = (scenario: Scenario): unknown => {
  let quoteCount = 0;
  const results = scenario.steps.map((step) => {
    const items = step.items ?? [];
    const isFollowUp = quoteCount > 0;
    quoteCount += 1;
    return { premium: computeQuotePremium(scenario.customer, items, isFollowUp) };
  });
  return { results };
};

