interface Policy {
  items: Item[];
  cap: number;
}

const policyInsuranceSum = (items: Item[]): number =>
  items.reduce((sum, item) => sum + (INSURANCE_VALUES[item.type] ?? 0), 0);

const computeClaim = (
  policy: Policy,
  incident: Incident,
): { payout: number; remainingCap: number } => {
  const totalPayout = incident.damages.reduce(
    (sum, damage) => sum + (damage.amount - DEDUCTIBLE),
    0,
  );
  return {
    payout: Math.floor(totalPayout),
    remainingCap: policy.cap - totalPayout,
  };
};

export const runScenario = (scenario: Scenario): unknown => {
  let quoteCount = 0;
  const policies: Policy[] = [];
  const results = scenario.steps.map((step) => {
    if (step.op === "claim") {
      const policy = policies[step.policy ?? 0];
      return computeClaim(policy, step.incident as Incident);
    }
    const items = step.items ?? [];
    const isFollowUp = quoteCount > 0;
    quoteCount += 1;
    policies.push({ items, cap: policyInsuranceSum(items) * CAP_MULTIPLIER });
    return { premium: computeQuotePremium(scenario.customer, items, isFollowUp) };
  });
  return { results };
};

