    extras += base * HIGH_ENCHANTMENT_RATE;
  }
  return extras;
};

interface PremiumBreakdown {
  withSurcharges: number;
  baseOnly: number;
}

const sumBy = <T>(items: T[], f: (item: T) => number): number =>
  items.reduce((sum, item) => sum + f(item), 0);

